export default function FAQPage() {
  usePageTitle('FAQ')

  // Inject FAQPage schema.org structured data for rich Google snippets
  useEffect(() => {
    const allQuestions = CATEGORIES.flatMap(cat =>
      cat.items.map(item => ({
        '@type': 'Question',
        name: item.q,
        acceptedAnswer: {
          '@type': 'Answer',
          text: item.a,
        },
      }))
    )
    const schema = {
      '@context': 'https://schema.org',
      '@type': 'FAQPage',
      mainEntity: allQuestions,
    }
    const script = document.createElement('script')
    script.type = 'application/ld+json'
    script.id = 'faq-schema'
    script.textContent = JSON.stringify(schema)
    document.head.appendChild(script)
    return () => {
      const el = document.getElementById('faq-schema')
      if (el) el.remove()
    }
  }, [])

  const [openItems, setOpenItems] = useState({})

  const toggleItem = (catIdx, itemIdx) => {
    const key = `${catIdx}-${itemIdx}`
    setOpenItems(prev => ({ ...prev, [key]: !prev[key] }))
  }

  return (
    <div className={s.page}>
      <SEO title="FAQ" description="Answers to 30+ common questions about Aura Alpha's autonomous bots, 83 strategies, broker connections, pricing, and risk controls. Updated for 2026." />
      <PublicNav />

      {/* Hero */}
      <section className={s.hero}>
        <h1 className={s.heroTitle}>
          Frequently Asked Questions
        </h1>
        <p className={s.heroSub}>
          Everything you need to know about Aura Alpha.
        </p>
      </section>

      {/* Category navigation */}
      <section className={s.catNavSection}>
        <div className={s.catNavRow}>
          {CATEGORIES.map((cat, i) => (
            <a
              key={i}
              href={`#faq-cat-${i}`}
              className={s.catNavLink}
              style={{
                background: `${cat.color}12`, border: `1px solid ${cat.color}30`,
                color: cat.color,
              }}
            >
              {cat.name}
              <span className={s.catNavCount} style={{
                background: `${cat.color}20`,
              }}>{cat.items.length}</span>
            </a>
          ))}
        </div>
      </section>

      {/* FAQ Categories */}
      <section className={s.faqSection}>
        {CATEGORIES.map((cat, catIdx) => (
          <div key={catIdx} id={`faq-cat-${catIdx}`} className={s.faqCategory}>
            <div className={s.catHeader}>
              <div className={s.catDot} style={{ background: cat.color }} />
              <h2 className={s.catTitle}>{cat.name}</h2>
              <span className={s.catCount} style={{
                background: `${cat.color}15`, color: cat.color,
              }}>{cat.items.length}</span>
            </div>

            {cat.items.map((item, itemIdx) => {
              const key = `${catIdx}-${itemIdx}`
              const isOpen = openItems[key]
              return (
                <div key={itemIdx} className={s.faqItem} style={{
                  borderBottom: `1px solid ${T.border}44`,
                }}>
                  <button
                    onClick={() => toggleItem(catIdx, itemIdx)}
                    className={s.faqQuestion}
                  >
                    <span className={s.faqQuestionText}>
                      {item.q}
                    </span>
                    <span className={isOpen ? s.faqToggleOpen : s.faqToggle}>+</span>
                  </button>
                  <div className={isOpen ? s.faqAnswerOpen : s.faqAnswerClosed}>
                    <p className={s.faqAnswerText}>
                      {item.a}
                    </p>
                  </div>
                </div>
              )
            })}
          </div>
        ))}
      </section>

      {/* Still have questions */}
      <section className={s.contactSection}>
        <div className={s.contactInner}>
          <h2 className={s.contactTitle}>
            Still Have Questions?
          </h2>
          <p className={s.contactSub}>
            Our team responds within 24 hours on business days.
          </p>
          <div className={s.contactButtons}>
            <a href="mailto:support@auraalpha.cc" className={s.emailBtn}>Email Support</a>
            <Link to="/contact-sales" className={s.salesBtn}>Contact Sales</Link>
          </div>
        </div>
      </section>

      <PublicFooter />
    </div>
  )
}
